#include <bits/stdc++.h>
using namespace std;

const int N=4e4+10;

int phi[N],s[N];

int euler_phi(int n){
    int ans=n;
    for(int i=2;i*i<=n;i++)
        if(n%i==0){
            ans=ans/i*(i-1);
            while(n%i==0)
                n/=i;
        }
    if(n>1)
        ans=ans/n*(n-1);
    return ans;
}

void init(){
    for(int i=1;i<N;i++)
        phi[i]=euler_phi(i)+(i==1),s[i]=s[i-1]+phi[i];
}

int main(){
    int n;
    init();
    scanf("%d",&n);
    printf("%d\n",s[n-1]*2-(n>1));
    return 0;
}
